def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 10:
            for a in range(10, 5, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    trig = np.sin(ratio * b * 1.3) * np.cos(ratio * a / (b + 1))
                    priority += val * trig * 2.3
            priority += (np.exp(ratio - 10) * np.sin(ratio * 1.7)) ** 2.2
            if i % 2 == 0:
                priority += np.log1p(ratio) * 7.5
            else:
                priority -= np.sqrt(ratio) * 5.5
            for c in range(1, 6):
                priority += np.sin(ratio * c * 2) / (c + 0.5)
        elif 6 < ratio <= 10:
            s = 0
            for m in range(1, 20):
                for n in range(1, m + 3):
                    s += ((ratio - 6) ** 4) * np.cos(ratio * m / (n + 1)) / (m * n + 1)
            priority = s * np.tanh(ratio - 6) * 12
            if bin_cap < item * 1.2:
                priority += np.sqrt(item * bin_cap) * 5
            else:
                priority -= np.exp(-1.5 * ratio) * 6
            for d in range(1, 5):
                if (i + d) % 4 == 0:
                    priority += np.sin(ratio * d * 1.5) * 1.7
                else:
                    priority -= np.cos(ratio * d * 1.5) * 1.7
        elif 3 <= ratio <= 6:
            priority = 0
            for p in range(1, 15):
                for q in range(1, p + 2):
                    part1 = ((ratio - 3) ** 3.5) / (p * q + 0.5)
                    part2 = np.sin(ratio * q) * np.cos(ratio * p / (q + 1))
                    priority += np.tanh(part1 * part2) * 3.1
            if bin_cap < item * 0.9:
                priority += np.log1p(item / bin_cap) * 6
            else:
                priority -= np.exp(-ratio) * 4.5
            priority += (np.sin(ratio * i * 0.9) + np.cos(ratio * i * 1.1)) * 2.1
        elif 1 < ratio < 3:
            total = 0
            for x in range(1, 25):
                term = ((ratio - 1) ** x) * np.cos(x * ratio * 1.3) / (x * 2.2)
                total += term
            priority = total - np.log(ratio + 0.1) * 8 + np.tanh(3 - ratio) * 4
            for y in range(1, 7):
                priority += ((3 - ratio) ** y) * np.sin(y * item * 2.2) / (y + 0.3)
            if bin_cap < item * 0.8:
                priority += np.sqrt(bin_cap / (item + 1)) * 7
            else:
                priority -= np.exp(-ratio * 1.3) * 5
        elif 0.5 <= ratio <= 1:
            s = 0
            for z in range(1, 18):
                s += ((1 - ratio) ** z) / (z ** 2 + 1) * np.sin(z * ratio * 3.5)
            penalty = 0
            if bin_cap < item * 0.7:
                penalty = np.log1p(item * bin_cap) * 8
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for w in range(1, 5):
                priority += np.cos(w * ratio * i) * ((ratio - 0.5) ** w) / (w + 0.5)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for u in range(1, 20):
                s += ((0.5 - ratio) ** u) / (u * 5) * np.cos(u * item * 1.5)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3) + 4)
            for v in range(1, 8):
                priority += ((0.5 - ratio) ** v) * np.sin(v * item * 1.7) * 0.9
        elif 0.05 <= ratio < 0.2:
            s = 0
            for aa in range(1, 15):
                s += ((0.2 - ratio) ** aa) / (aa * 4) * np.cos(aa * ratio * 3)
            priority = s + 2 / (bin_cap + 6)
            if int(item * 1.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5.2
            for bb in range(1, 10):
                priority += ((0.2 - ratio) ** bb) / (bb * 8) * np.cos(item * bb * 1.2)
        else:
            s = 0
            for cc in range(1, 12):
                s += ((0.05 - ratio) ** cc) / (cc * 6) * np.sin(cc * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for dd in range(1, 9):
                priority += ((0.05 - ratio) ** dd) / (dd * 9) * np.cos(item * dd * 0.95)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.5) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.75
        priorities[i] = priority
    return priorities
